import { test, expect } from '@playwright/test';
import { signInAs, openChannel, sendMessage } from './fixtures';

test('deleted mention message retracts visible banner', async ({ browser }) => {
  const aliceCtx = await browser.newContext();
  const bobCtx = await browser.newContext();
  const alice = await aliceCtx.newPage();
  const bob = await bobCtx.newPage();

  await signInAs(alice, 'alice');
  await signInAs(bob, 'bob');

  await openChannel(alice, 'c1');
  await openChannel(bob, 'c1');

  // Alice mentions bob; bob's banner appears.
  await sendMessage(alice, 'hey @m_bob, look at this draft');
  const banner = bob.locator('[data-test=in-app-banner]');
  await expect(banner).toBeVisible();

  // Capture the message id from alice's view so we can delete it.
  const lastMessage = alice.locator('[data-test=message-row]').last();
  const messageId = await lastMessage.getAttribute('data-test-message-id');
  expect(messageId).toBeTruthy();

  // Alice deletes the message before bob opens the banner.
  await lastMessage.hover();
  await lastMessage.locator('[data-test=message-overflow]').click();
  await alice.locator('[data-test=message-delete]').click();
  await alice.locator('[data-test=confirm-delete]').click();

  // Bob's banner should retract (REQ-006).
  await expect(banner).toBeHidden();
});
